    ["first"] = { -- Hidden first name prompts (Name: first-last letter / state / age)
        [1] = "%s---%s frá %s, fjármálasnillingur %s ára gamall, leiðir viðskiptavini til árangurs með aðlögunarhæfni og sérþekkingu. Ótrúleg hæfni hans til að leysa vandamál gerir hann að mikilvægasta manninum fyrir flókin fjármálamál.",
