        [7] = "%s---%s í %s, %s ára, veitir viðskiptavinum siðferðislegar venjur og nýstárlegar aðferðir. Með skarpa auga fyrir áhættustjórnun tryggir hann fjármálastöðugleika viðskiptavina.",
        [8] = "%s---%s frá %s, %s ára, setur ný viðmið í bankageiranum með sérfræðiþekkingu sinni. Geta hans til að sjá fyrir markaðsþróun hjálpar viðskiptavinum að taka upplýstar ákvarðanir.",
        [9] = "%s---%s frá %s, %s ára, hvetur til fjárhagslegs sjálfstæðis með hollustu og aðlögunarhæfni. Ástríða hans fyrir að fræða viðskiptavini um fjármálalæsi er virðingarverð.",
        [10] = "%s---%s frá %s, %s ára, endurskilgreinir iðnaðinn með nýstárlegri nálgun við bankastarfsemi. Þekktur fyrir hugsun sína utan kassa, kynnir hann skapandi fjármálaúrræði.",
        [11] = "%s---%s í %s, %s ára, tryggir fjárhagslegt velferð viðskiptavina með mikilli reynslu. Víða net iðnaðartengsla hans gagnast viðskiptavinum á ýmsum sviðum.",
        [12] = "%s---%s frá %s, %s ára, veitir sérsniðnar lausnir, sem skilur eftir varanleg áhrif á viðskiptavini. Beinskeytt nálgun hans stuðlar að sterkri trausti við viðskiptavini hans.",
        [13] = "%s---%s í %s, %s ára, er upprennandi stjarna með ósamræmdri nýsköpun og traustleika. Hollusta hans við stöðugt nám gerir hann sérstakan í samkeppnishæfu bankalandslagi.",
        [14] = "%s---%s frá %s, %s ára, leiðir viðskiptavini til fjármálaárangurs með einstakri sérfræðiþekkingu. Geta hans til að finna falin tækifæri tryggir fjárhagslegan vöxt viðskiptavina.",
        [15] = "%s---%s í %s, %s ára, veitir viðskiptavinum siðferðislegar venjur og færir þá til hagsældar. Þátttaka hans í ýmsum góðgerðarátaksverkefnum endurspeglar hollustu hans við að bæta samfélagið.",
