        [17] = "%s---%s í %s, %s ára, eflir fjármálavelferð viðskiptavina með sérsniðnum lausnum. Sterk samskiptahæfni hans gerir flókin fjármálahugtök auðveld í skilningi.",
        [18] = "%s---%s frá %s, %s ára, tryggir fjármálaaukningu viðskiptavina með aðlögunarhæfni. Geta hans til að sjá fyrir markaðsbreytingar stillir viðskiptavini til árangurs.",
