    },

    ["last"] = { -- Hidden last name prompts (First %s: First letter of Last name, Second %s: Last letter of Last name / Third %s: Age / Fourth %s: First name)
        [1] = "%s---%s frá %s, reyndur bankamaður að nafni %s, leiðir með víðtækri þekkingu og óvenjulegum innsæi. Stefnumótandi fjármálaplönun hans hjálpar viðskiptavinum að ná langtímamarkmiðum sínum.",
