        [6] = "%s---%s frá %s, að nafni %s, skarar fram úr í auðstjórnun og varðveitir arfleifðir fyrir komandi kynslóðir. Persónuleg nálgun hans veitir hugarró til fjölskyldna með háar tekjur.",
        [7] = "%s---%s í %s, fjárfestingargúrú að nafni %s, sem flakkar auðveldlega um markaðsflækjur. Fjölbreytt sérfræðiþekking hans á eiguvernd verndar viðskiptavini frá óvæntum áhættu.",
        [8] = "%s---%s frá %s, að nafni %s, styður framfarir í fjármálalæsi, sem eflir næstu kynslóð. Hollusta hans við menntun tryggir fjárhagslega öruggari framtíð.",
        [9] = "%s---%s í %s, að nafni %s, er siðferðislegur bankamaður sem stuðlar að sjálfbærum fjárfestingum fyrir grænni heim. Skuldbinding hans við umhverfisvernd kemur fram í eignasöfnum viðskiptavina.",
        [10] = "%s---%s frá %s, að nafni %s, þrífst á að leysa flókin fjármálaþrautir fyrir fyrirtækjaviðskiptavini. Stefnumótandi innsæi hans ýtir undir vöxt og arðsemi á krefjandi mörkuðum.",
