        [13] = "%s---%s í %s, að nafni %s, sérhæfir sig í sameiningum og yfirtökum og skipuleggur farsæla samninga fyrir fyrirtækjaviðskiptavini. Skörp samningafærni hans hámarkar gildi fyrir alla hagsmunaaðila.",
        [14] = "%s---%s frá %s, að nafni %s, veitir fjölbreyttum frumkvöðlum styrk og brýtur fjármálabil fyrir samfélög sem eru ekki fullnægjandi. Skuldbinding hans við innifalið fjármál ýtir undir efnahagslegt jafnræði.",
        [15] = "%s---%s í %s, að nafni %s, hjálpar fjölskyldum að tryggja framtíð sína með skynsamlegri arfleifðar skipulagningu. Samúð hans veitir leiðbeiningar í flækjur ríkidæmiskraftsins.",
        [16] = "%s---%s frá %s, reyndur bankamaður að nafni %s, sem skarar fram úr í fyrirtækjafjárhagslegum málum og veitir stefnumótandi lausnir fyrir fjölþjóðafyrirtæki. Fjármálavit hans ýtir undir árangur á alþjóðlegum mörkuðum.",
