        [18] = "%s---%s frá %s, að nafni %s, tæknilega hugaður bankamaður sem nýtir stafrænar nýjungar til að auka reynslu viðskiptavina. Skuldbinding hans við örugga bankastarfsemi eykur viðskiptavinaverðmæti.",
        [19] = "%s---%s í %s, að nafni %s, hvetur til fjármálalæsi á meðal ungmenna og hvetur næstu kynslóð skynsamra fjárfesta. Fræðsluáhrif hans skapa traustan grunn fyrir fjárhagslegan árangur.",
        [20] = "%s---%s frá %s, einhverskonar leiðtogi að nafni %s, sem ýtir undir umbreytingarbreytingar í bankageiranum með sjálfbærum venjum. Forysta hans mótar ábyrgara og áhrifameiri fjármálasviði.",
    },

    ["residence"] = { -- Hidden residence prompts (First %s: First name / Second %s: Age / Third %s: First letter of Residence, Fourth %s: Last letter of Residence)
        [1] = "Kynntu þér %s, undrabarn bankamála. Á aðeins %s árum er hann einn yngsti og snjallasti gagnafræðingur í fylkinu %s---%s. Framtíðarsýn með óbilandi heiðarleika, Alex leitast við að endurhugsa bankageirann og skilja eftir sig varanleg áhrif á framtíð fjárhagsviðskiptavina.",
        [2] = "Kynnum %s, fjármálasnillingur bankamála, rétt nýkominn %s ára og þegar einn bjartasti gagnafræðingur í líflegu fylkinu %s---%s. Með framtíðarsýn og óbilandi siðferði miðar hann að því að endurhugsa bankageirann og hafa varanleg áhrif á fjárhagslega ferð viðskiptavina.",
        [3] = "Stígið inn í heim %s, undraverður bankamaður sem, á unga aldri %s, stendur á meðal bestu gagnafræðinga í bustling fylkinu %s---%s. Leiddur af framtíðarsýn og óbilandi heiðarleika leitast hann við að endurhugsa bankalandslagið, leiða viðskiptavini sína að blómstrandi fjárhagslegri framtíð.",
